import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../../components/Navbar';
import Footer from '../../components/Footer';
import PropertyCard from '../../components/PropertyCard';
import API from '../../services/api';
import './Home.css';

const Home = () => {
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchFilters, setSearchFilters] = useState({
    city: '',
    propertyType: '',
    minPrice: '',
    maxPrice: ''
  });

  useEffect(() => {
    fetchProperties();
  }, []);

  const fetchProperties = async (filters = {}) => {
    try {
      setLoading(true);
      const queryParams = new URLSearchParams(filters).toString();
      const response = await API.get(`/properties?${queryParams}`);
      setProperties(response.data.data);
    } catch (error) {
      console.error('Error fetching properties:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    fetchProperties(searchFilters);
  };

  const handleFilterChange = (e) => {
    setSearchFilters({
      ...searchFilters,
      [e.target.name]: e.target.value
    });
  };

  return (
    <div className="home">
      <Navbar />

      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <h1>Find Your Dream Home</h1>
          <p>Discover the perfect property from our extensive listings</p>

          {/* Search Form */}
          <div className="search-container">
            <form className="search-form" onSubmit={handleSearch}>
              <input
                type="text"
                name="city"
                placeholder="Location / City"
                className="search-input"
                value={searchFilters.city}
                onChange={handleFilterChange}
              />
              <select
                name="propertyType"
                className="search-input"
                value={searchFilters.propertyType}
                onChange={handleFilterChange}
              >
                <option value="">Property Type</option>
                <option value="House">House</option>
                <option value="Apartment">Apartment</option>
                <option value="Villa">Villa</option>
                <option value="Condo">Condo</option>
                <option value="Commercial">Commercial</option>
              </select>
              <input
                type="number"
                name="minPrice"
                placeholder="Min Price"
                className="search-input"
                value={searchFilters.minPrice}
                onChange={handleFilterChange}
              />
              <input
                type="number"
                name="maxPrice"
                placeholder="Max Price"
                className="search-input"
                value={searchFilters.maxPrice}
                onChange={handleFilterChange}
              />
              <button type="submit" className="btn-search">
                🔍 Search
              </button>
            </form>
          </div>
        </div>
      </section>

      {/* Properties Section */}
      <section className="properties-section">
        <div className="container">
          <h2 className="section-title">Featured Properties</h2>
          <p className="section-subtitle">
            Explore our hand-picked selection of premium properties
          </p>

          {loading ? (
            <div className="loading">
              <p>Loading properties...</p>
            </div>
          ) : properties.length === 0 ? (
            <div className="no-properties">
              <p>No properties found. Try adjusting your search filters.</p>
            </div>
          ) : (
            <div className="property-grid">
              {properties.map((property) => (
                <PropertyCard key={property._id} property={property} />
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Features Section */}
      <section className="features-section">
        <div className="container">
          <h2 className="section-title">Why Choose Us</h2>
          <p className="section-subtitle">
            We make finding your dream home simple and stress-free
          </p>

          <div className="features-grid">
            <div className="feature-card">
              <div className="feature-icon">🔍</div>
              <h3>Easy Search</h3>
              <p>Find properties quickly with our advanced search filters</p>
            </div>

            <div className="feature-card">
              <div className="feature-icon">📅</div>
              <h3>Schedule Visits</h3>
              <p>Book property visits at your convenience</p>
            </div>

            <div className="feature-card">
              <div className="feature-icon">💬</div>
              <h3>24/7 Support</h3>
              <p>Chat with our AI assistant anytime you need help</p>
            </div>

            <div className="feature-card">
              <div className="feature-icon">✅</div>
              <h3>Verified Listings</h3>
              <p>All properties are verified by our expert agents</p>
            </div>
          </div>
        </div>
      </section>

      <Footer />
    </div>
  );
};

export default Home;
